package com.yottastudios.ns.collabspace.feedback.entity;

import com.baomidou.mybatisplus.annotation.TableName;
import com.yottastudios.ns.collabspace.core.entity.BaseEntity;
import lombok.AllArgsConstructor;
import lombok.Data;
import lombok.EqualsAndHashCode;
import lombok.NoArgsConstructor;
import lombok.experimental.Accessors;
import lombok.experimental.SuperBuilder;

import java.io.Serial;
import java.io.Serializable;
import java.time.LocalDateTime;

@EqualsAndHashCode(callSuper = true)
@Data
@NoArgsConstructor
@AllArgsConstructor
@Accessors(chain = true)
@SuperBuilder
@TableName(keepGlobalPrefix = true, value = "feedback", autoResultMap = true)
public class FeedbackEntity extends BaseEntity implements Serializable {

    @Serial
    private static final long serialVersionUID = 1L;

    /** Mattermost消息ID，用于关联同一条消息的增/改/删 */
    private String postId;

    /** 反馈人标识 */
    private String userId;

    /** 反馈人昵称 */
    private String userName;

    /** 反馈时间 */
    private LocalDateTime feedbackTime;

    /** 文档类型 */
    private String docType;

    /** 反馈类型（lag/bug/feat/other） */
    private String feedbackType;

    /** 相关链接 */
    private String relatedLink;

    /** 反馈内容 */
    private String content;

    /** 附件URL列表（JSON数组，MinIO地址） */
    private String attachments;

    /** 其他信息 */
    private String extraInfo;

    /** 来源（sentry/mm） */
    private String source;

    /** 反馈状态（0-未处理 1-已处理） */
    private Integer status;
}

