import com.yottastudios.ns.collabspace.feedback.service.IFeedbackService;
import com.yottastudios.ns.collabspace.feedback.vo.FeedbackVo;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.ApiResource;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.GetResource;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.PostResource;
import io.swagger.v3.oas.annotations.Operation;
import io.swagger.v3.oas.annotations.tags.Tag;
import jakarta.annotation.Resource;
import jakarta.validation.Valid;
import lombok.extern.slf4j.Slf4j;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestPart;
import org.springframework.web.bind.annotation.RestController;
import org.springframework.web.multipart.MultipartFile;

import java.util.List;

@Slf4j
@RestController
@Tag(name = "Feedback")
@ApiResource(path = "/feedback")
public class FeedbackController {

    @Resource
    private IFeedbackService feedbackService;

    /**
     * 前端反馈提交（替代Sentry）
     */
    @PostResource(path = "/submit", requiredPermission = false)
    @Operation(summary = "Submit feedback")
    public ResponseData<Void> submitFeedback(
            @RequestPart(value = "data") @Valid FeedbackSubmitRo ro,
            @RequestPart(value = "files", required = false) List<MultipartFile> files) {
        log.info("[lbl][2087-消息推送][Feedback][SUBMIT] 收到站内反馈, feedbackType={}, relatedLink={}, fileCount={}",
                ro.getFeedbackType(), ro.getRelatedLink(), files != null ? files.size() : 0);
        feedbackService.submitFeedback(ro, files);
        return ResponseData.success();
    }

    /**
     * 管理后台分页查询
     */
    @GetResource(path = "/list", requiredPermission = false)
    @Operation(summary = "List feedback")
    public ResponseData<IPage<FeedbackVo>> listFeedback(FeedbackListRo ro) {
        return ResponseData.success(feedbackService.listFeedback(ro));
    }

    /**
     * 更新反馈状态
     */
    @PostResource(path = "/update-status", requiredPermission = false)
    @Operation(summary = "Update feedback status")
    public ResponseData<Void> updateFeedbackStatus(@RequestBody @Valid FeedbackUpdateStatusRo ro) {
        log.info("[lbl][2087-消息推送][Feedback][UPDATE-STATUS] 更新反馈状态请求, feedbackId={}, status={}", ro.getFeedbackId(), ro.getStatus());
        feedbackService.updateFeedbackStatus(ro);
        return ResponseData.success();
    }
}

