package com.yottastudios.ns.collabspace.workspace.enums;

import com.fasterxml.jackson.annotation.JsonValue;
import com.yottastudios.ns.collabspace.core.exception.BusinessException;
import lombok.AllArgsConstructor;
import lombok.Getter;

import java.util.List;

@Getter
@AllArgsConstructor
public enum SpaceNodeTypeEnum {

    FOLDER(1, null),
    DATASHEET(2, 2),
    FORM(3,3),
    DASHBOARD(4,4),
    MIRROR(5,5),
    LUCKYSHEET(6, 200),
    AFFINE(7, 8),
    OUTLINE(8,210),
    ONLYOFFICE_EXCEL(9, null),
    ONLYOFFICE_WORD(11, null),
    ONLYOFFICE_PPT(12, null),
    LINK(10, null),
    NEXTCLOUD(13, null),

    ;

    @JsonValue
    private final Integer value;

    @JsonValue
    private final Integer thirdValue; // thirdValue用于处理和apitable交互时, 原apitable的node枚举同本类的value冲突的问题, 其它应用可不填

    public static final List<SpaceNodeTypeEnum> APITABLE_TYPES = List.of(DATASHEET, FORM, DASHBOARD, MIRROR);
    public static final List<SpaceNodeTypeEnum> OUTLINE_TYPES = List.of(OUTLINE);
    public static final List<SpaceNodeTypeEnum> ONLYOFFICE_TYPES = List.of(ONLYOFFICE_EXCEL, ONLYOFFICE_WORD, ONLYOFFICE_PPT);
    public static final List<SpaceNodeTypeEnum> AFFINE_TYPES = List.of(AFFINE);

    public static SpaceNodeTypeEnum fromValue(Integer value) {
        for (SpaceNodeTypeEnum type : SpaceNodeTypeEnum.values()) {
            if (type.getValue().equals(value)) {
                return type;
            }
        }
        throw new BusinessException(SpaceNodeException.INVALID_TYPE);
    }

    public static final String FOLDER_DESC = "文件夹";
    public static final String DATASHEET_DESC = "智能表格";
    public static final String FORM_DESC = "神奇表单";
    public static final String DASHBOARD_DESC = "仪表盘";
    public static final String MIRROR_DESC = "镜像";
    public static final String LUCKYSHEET_DESC = "表格(luckysheet)";
    public static final String AFFINE_DESC = "智能文档";
    public static final String OUTLINE_DESC = "outline";
    public static final String ONLYOFFICE_DESC = "表格";
    public static final String ONLYOFFICE_WORD_DESC = "word";
    public static final String ONLYOFFICE_PPT_DESC = "ppt";
    public static final String LINK_DESC = "链接";
    public static final String NEXTCLOUD_DESC = "nextcloud文件";

    public static final String ENUM_MAPPINGS =
            "1: " + FOLDER_DESC + ", " +
            "2: " + DATASHEET_DESC + ", " +
            "3: " + FORM_DESC + ", " +
            "4: " + DASHBOARD_DESC + ", " +
            "5: " + MIRROR_DESC + ", " +
            "6: " + LUCKYSHEET_DESC + ", " +
            "7: " + AFFINE_DESC + ", " +
            "8: " + OUTLINE_DESC + ", " +
            "9: " + ONLYOFFICE_DESC + ", " +
            "11: " + ONLYOFFICE_WORD_DESC + ", " +
            "12: " + ONLYOFFICE_PPT_DESC + ", " +
            "10: " + LINK_DESC + ", " +
            "13: " + NEXTCLOUD_DESC;

    public String getDescription() {
        return switch (this) {
            case FOLDER -> FOLDER_DESC;
            case DATASHEET -> DATASHEET_DESC;
            case FORM -> FORM_DESC;
            case DASHBOARD -> DASHBOARD_DESC;
            case MIRROR -> MIRROR_DESC;
            case LUCKYSHEET -> LUCKYSHEET_DESC;
            case AFFINE -> AFFINE_DESC;
            case OUTLINE -> OUTLINE_DESC;
            case ONLYOFFICE_EXCEL -> ONLYOFFICE_DESC;
            case ONLYOFFICE_WORD -> ONLYOFFICE_WORD_DESC;
            case ONLYOFFICE_PPT -> ONLYOFFICE_PPT_DESC;
            case LINK -> LINK_DESC;
            case NEXTCLOUD -> NEXTCLOUD_DESC;
        };
    }
}

