  1→// 一键反馈 组件
  2→import { useKeyPress } from 'ahooks';
  3→import { Checkbox, Form, Input, Modal, type UploadFile } from 'antd';
  4→import dayjs from 'dayjs';
  5→import { memo, useMemo, useState } from 'react';
  6→
  7→import { localFeedbackButtonOffset } from '@/common/localVar';
  8→import { antdApp } from '@/common/pageInit.tsx';
  9→import { I18nText } from '@/components/Common/I18nText/I18nText.tsx';
 10→import { CustomUpload } from '@/components/CustomUpload/CustomUpload.tsx';
 11→import { EdgeSnapButton } from '@/components/EdgeSnapButton/EdgeSnapButton.tsx';
 12→import { useStateLocal } from '@/hooks/useStateLocal.ts';
 13→import { t } from '@/i18n';
 14→import { FeedbackFill } from '@/icon';
 15→import { useRootSelector } from '@/store';
 16→import { getCurrUser } from '@/store/system.ts';
 17→import { captureMessage } from '@/utils/sentry.ts';
 18→
 19→type IFormData = {
 20→  nickName?: string;
 21→  href?: string;
 22→  types?: string[];
 23→  desc?: string;
 24→  files?: UploadFile[];
 25→};
 26→
 27→export const FeedbackSubmissionBase = () => {
 28→  const me = useRootSelector(getCurrUser);
 29→  useKeyPress('ctrl.shift.h', () => {
 30→    setOpen(true);
 31→  });
 32→  const types = useMemo(() => {
 33→    return [
 34→      {
 35→        label: <I18nText>feedbackTypeLag</I18nText>,
 36→        value: 'lag',
 37→      },
 38→      {
 39→        label: <I18nText>feedbackTypeBug</I18nText>,
 40→        value: 'bug',
 41→      },
 42→      {
 43→        label: <I18nText>feedbackTypeFeature</I18nText>,
 44→        value: 'feat',
 45→      },
 46→      {
 47→        label: <I18nText>feedbackTypeOther</I18nText>,
 48→        value: 'other',
 49→      },
 50→    ];
 51→  }, []);
 52→  const [offset, setOffset] = useStateLocal(localFeedbackButtonOffset.get, localFeedbackButtonOffset.set);
 53→  const [open, setOpen] = useState(false);
 54→  const [form] = Form.useForm<IFormData>();
 55→  const onConfirm = () => {
 56→    form.validateFields().then(() => {
 57→      const data = form.getFieldsValue();
 58→      captureMessage(`${me.nickName}: submitted feedback in ${dayjs().format('YYYY-MM-DD HH:mm')}`, 'info', {
 59→        desc: data.desc,
 60→        types: data.types?.toString(),
 61→        // eslint-disable-next-line @typescript-eslint/no-shadow
 62→      }, data.types?.map((t) => {
 63→        return {
 64→          key: `feedback-${t}`,
 65→          value: 'true',
 66→        };
 67→      }), data.files?.map((o) => o.originFileObj as File));
 68→      antdApp.message.success(<I18nText>feedbackSuccess</I18nText>);
 69→      setOpen(false);
 70→    });
 71→  };
 72→  return (
 73→    <>
 74→      <Modal
 75→        open={open}
 76→        onCancel={() => {
