// 反馈收集
import { fetchData } from '@/utils/request';

export enum FeedbackFlag {
  /** 卡顿 */
  Lag = 'lag',
  /** bug */
  Bug = 'bug',
  /** 功能需求 */
  Feat = 'feat',
  /** 其他 */
  Other = 'other',
}

interface ISubmitFeedbackParams {
  data: {
    feedbackType: FeedbackFlag;
    content?: string;
    /** location.href */
    relatedLink: string;
    /** SpaceTreeNodeType, 非文档页面为0 */
    docType: string;
  };
  files?: File[];
}

export const submitFeedback = (params: ISubmitFeedbackParams) => {
  const data = new FormData();
  data.append('data', new Blob([JSON.stringify(params.data)], { type: 'application/json' }));
  params.files?.forEach((file) => {
    data.append('files', file);
  });
  return fetchData({
    url: '/api/v1/feedback/submit',
    method: 'POST',
    data,
  });
};

