191→
192→        if (ro.getStatus() != null) {
193→            wrapper.eq(FeedbackEntity::getStatus, ro.getStatus());
194→        }
195→        if (StrUtil.isNotBlank(ro.getDocType())) {
196→            wrapper.eq(FeedbackEntity::getDocType, ro.getDocType());
