280→                String keyPath = "feedback/mm/" + LocalDate.now().format(DateTimeFormatter.BASIC_ISO_DATE)
281→                        + "/" + UUID.randomUUID() + "_" + fileId;
282→                ossTemplate.upload(bucketName, new ByteArrayInputStream(fileData), keyPath);
283→                String url = constProperties.getOssBucketByAsset().getResourceUrl() + "/" + keyPath;
