package com.yottastudios.ns.collabspace.feedback.service.impl;

import cn.hutool.core.util.StrUtil;
import cn.hutool.json.JSONUtil;
import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;
import com.baomidou.mybatisplus.core.metadata.IPage;
import com.baomidou.mybatisplus.extension.plugins.pagination.Page;
import com.baomidou.mybatisplus.extension.service.impl.ServiceImpl;
import com.yottastudios.ns.collabspace.core.exception.BusinessException;
import com.yottastudios.ns.collabspace.feedback.entity.FeedbackEntity;
import com.yottastudios.ns.collabspace.feedback.enums.FeedbackSource;
import com.yottastudios.ns.collabspace.feedback.enums.FeedbackStatus;
import com.yottastudios.ns.collabspace.feedback.mapper.FeedbackMapper;
import com.yottastudios.ns.collabspace.feedback.ro.FeedbackListRo;
import com.yottastudios.ns.collabspace.feedback.ro.FeedbackSubmitRo;
import com.yottastudios.ns.collabspace.feedback.ro.FeedbackUpdateStatusRo;
import com.yottastudios.ns.collabspace.feedback.ro.MmFeedbackWebhookRo;
import com.yottastudios.ns.collabspace.feedback.service.IFeedbackService;
import com.yottastudios.ns.collabspace.feedback.vo.FeedbackVo;
import com.yottastudios.ns.collabspace.shared.cache.bean.LoginUserDto;
import com.yottastudios.ns.collabspace.shared.cache.service.LoginUserCacheService;
import com.yottastudios.ns.collabspace.shared.config.properties.ConstProperties;
import com.yottastudios.ns.collabspace.shared.config.properties.MattermostProperties;
import com.yottastudios.ns.collabspace.shared.context.SessionContext;
import com.yottastudios.ns.collabspace.starter.oss.core.OssClientTemplate;
import com.yottastudios.ns.collabspace.third.feign.MattermostMessageFeign;
import jakarta.annotation.Resource;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;
import org.springframework.web.multipart.MultipartFile;

import java.io.ByteArrayInputStream;
import java.io.IOException;
import java.time.LocalDate;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.util.ArrayList;
import java.util.List;
import java.util.UUID;

@Slf4j
@Service
public class FeedbackServiceImpl extends ServiceImpl<FeedbackMapper, FeedbackEntity> implements IFeedbackService {

    @Resource
    private FeedbackMapper feedbackMapper;

    @Resource
    private OssClientTemplate ossTemplate;

    @Resource
    private ConstProperties constProperties;

    @Resource
    private MattermostMessageFeign mattermostMessageFeign;

    @Resource
    private MattermostProperties mattermostProperties;

    @Resource
    private LoginUserCacheService loginUserCacheService;

    @Override
    public void submitFeedback(FeedbackSubmitRo ro, List<MultipartFile> files) {
        Long userId = SessionContext.getUserId();
        log.info("[lbl][2087-消息推送][Feedback][CREATE] 提交站内反馈, userId={}, feedbackType={}", userId, ro.getFeedbackType());

        // 上传附件到MinIO
        List<String> attachmentUrls = uploadFilesToMinio(files);

        FeedbackEntity entity = FeedbackEntity.builder()
                .userId(String.valueOf(userId))
                .feedbackTime(LocalDateTime.now())
                .docType(ro.getDocType())
                .feedbackType(ro.getFeedbackType())
                .relatedLink(ro.getRelatedLink())
                .content(ro.getContent())
                .attachments(attachmentUrls.isEmpty() ? null : JSONUtil.toJsonStr(attachmentUrls))
                .source(FeedbackSource.SENTRY.getCode())
                .status(FeedbackStatus.UNPROCESSED.getCode())
                .build();

        feedbackMapper.insert(entity);
        log.info("[lbl][2087-消息推送][Feedback][CREATE] 站内反馈提交成功, id={}, userId={}", entity.getId(), userId);
    }

    @Override
    public void mmWebhookFeedback(MmFeedbackWebhookRo ro) {
        String action = StrUtil.blankToDefault(ro.getAction(), "create");
        log.info("[lbl][2087-消息推送][Feedback][{}] MM消息同步, postId={}, nickName={}, messageId={}, fileCount={}",
                action.toUpperCase(), ro.getPostId(), ro.getFeedbackNickName(), ro.getMessageId(),
                ro.getFiles() != null ? ro.getFiles().size() : 0);

        switch (action) {
            case "create" -> mmHandleCreate(ro);
            case "update" -> mmHandleUpdate(ro);
            case "delete" -> mmHandleDelete(ro);
            default -> log.warn("[lbl][2087-消息推送][Feedback] 未知action={}, postId={}", action, ro.getPostId());
        }
    }

    private void mmHandleCreate(MmFeedbackWebhookRo ro) {
        List<String> attachmentUrls = downloadMmFiles(ro);
        LocalDateTime feedbackTime = parseFeedbackTime(ro.getFeedbackTime());
        String extraInfo = buildExtraInfo(ro.getMessageId());

        FeedbackEntity entity = FeedbackEntity.builder()
                .postId(ro.getPostId())
                .userId(ro.getFeedbackNickName())
                .userName(ro.getFeedbackNickName())
                .feedbackTime(feedbackTime)
                .content(ro.getContent())
                .attachments(attachmentUrls.isEmpty() ? null : JSONUtil.toJsonStr(attachmentUrls))
                .extraInfo(extraInfo)
                .source(FeedbackSource.MM.getCode())
                .status(FeedbackStatus.UNPROCESSED.getCode())
                .build();

        feedbackMapper.insert(entity);
        log.info("[lbl][2087-消息推送][Feedback][CREATE] 写入成功, id={}, postId={}, nickName={}",
                entity.getId(), ro.getPostId(), ro.getFeedbackNickName());
    }

    private void mmHandleUpdate(MmFeedbackWebhookRo ro) {
        FeedbackEntity existing = findByPostId(ro.getPostId());
        if (existing == null) {
            log.warn("[lbl][2087-消息推送][Feedback][UPDATE] postId={} 记录不存在, 降级为create", ro.getPostId());
            mmHandleCreate(ro);
            return;
        }

        List<String> attachmentUrls = downloadMmFiles(ro);
        existing.setContent(ro.getContent());
        existing.setAttachments(attachmentUrls.isEmpty() ? null : JSONUtil.toJsonStr(attachmentUrls));
        existing.setFeedbackTime(parseFeedbackTime(ro.getFeedbackTime()));
        existing.setExtraInfo(buildExtraInfo(ro.getMessageId()));
        feedbackMapper.updateById(existing);
        log.info("[lbl][2087-消息推送][Feedback][UPDATE] 更新成功, id={}, postId={}", existing.getId(), ro.getPostId());
    }

    private void mmHandleDelete(MmFeedbackWebhookRo ro) {
        FeedbackEntity existing = findByPostId(ro.getPostId());
        if (existing == null) {
            log.warn("[lbl][2087-消息推送][Feedback][DELETE] postId={} 记录不存在, 忽略", ro.getPostId());
            return;
        }

        existing.setIsDeleted(1);
        feedbackMapper.updateById(existing);
        log.info("[lbl][2087-消息推送][Feedback][DELETE] 逻辑删除成功, id={}, postId={}", existing.getId(), ro.getPostId());
    }

    private FeedbackEntity findByPostId(String postId) {
        if (StrUtil.isBlank(postId)) {
            return null;
        }
        return lambdaQuery()
                .eq(FeedbackEntity::getPostId, postId)
                .eq(FeedbackEntity::getSource, FeedbackSource.MM.getCode())
                .eq(FeedbackEntity::getIsDeleted, 0)
                .last("LIMIT 1")
                .one();
    }

    private List<String> downloadMmFiles(MmFeedbackWebhookRo ro) {
        List<String> fileIds = ro.getFiles() != null
                ? ro.getFiles().stream().map(MmFeedbackWebhookRo.MmFileInfo::getFileId).toList()
                : List.of();
        return downloadMmFilesAndUpload(fileIds);
    }

    private LocalDateTime parseFeedbackTime(String feedbackTimeStr) {
        if (StrUtil.isNotBlank(feedbackTimeStr)) {
            try {
                return LocalDateTime.parse(feedbackTimeStr, DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss"));
            } catch (Exception e) {
                log.warn("[lbl][2087-消息推送][Feedback] feedbackTime解析失败, 使用当前时间, raw={}", feedbackTimeStr);
            }
        }
        return LocalDateTime.now();
    }

    private String buildExtraInfo(String messageId) {
        return StrUtil.isNotBlank(messageId)
                ? JSONUtil.toJsonStr(cn.hutool.core.map.MapUtil.of("messageId", messageId))
                : null;
    }

    @Override
    public IPage<FeedbackVo> listFeedback(FeedbackListRo ro) {
        int pageNum = ro.getPageNum() != null ? ro.getPageNum() : 1;
        int pageSize = ro.getPageSize() != null ? ro.getPageSize() : 20;

        LambdaQueryWrapper<FeedbackEntity> wrapper = new LambdaQueryWrapper<>();
        wrapper.eq(FeedbackEntity::getIsDeleted, 0);

        if (ro.getStatus() != null) {
            wrapper.eq(FeedbackEntity::getStatus, ro.getStatus());
        }
        if (StrUtil.isNotBlank(ro.getDocType())) {
            wrapper.eq(FeedbackEntity::getDocType, ro.getDocType());
        }
        if (StrUtil.isNotBlank(ro.getFeedbackType())) {
            wrapper.eq(FeedbackEntity::getFeedbackType, ro.getFeedbackType());
        }
        if (StrUtil.isNotBlank(ro.getStartDate())) {
            try {
                LocalDate startDate = LocalDate.parse(ro.getStartDate(), DateTimeFormatter.ISO_LOCAL_DATE);
                wrapper.ge(FeedbackEntity::getFeedbackTime, startDate.atStartOfDay());
            } catch (java.time.format.DateTimeParseException e) {
                throw new BusinessException("开始日期格式错误，应为yyyy-MM-dd");
            }
        }
        if (StrUtil.isNotBlank(ro.getEndDate())) {
            try {
                LocalDate endDate = LocalDate.parse(ro.getEndDate(), DateTimeFormatter.ISO_LOCAL_DATE);
                wrapper.le(FeedbackEntity::getFeedbackTime, endDate.plusDays(1).atStartOfDay());
            } catch (java.time.format.DateTimeParseException e) {
                throw new BusinessException("结束日期格式错误，应为yyyy-MM-dd");
            }
        }
        if (StrUtil.isNotBlank(ro.getKeyword())) {
            wrapper.like(FeedbackEntity::getContent, ro.getKeyword());
        }

        wrapper.orderByDesc(FeedbackEntity::getFeedbackTime);

        IPage<FeedbackEntity> page = feedbackMapper.selectPage(new Page<>(pageNum, pageSize), wrapper);

        return page.convert(this::toVo);
    }

    @Override
    public void updateFeedbackStatus(FeedbackUpdateStatusRo ro) {
        log.info("[lbl][2087-消息推送][Feedback][UPDATE] 更新反馈状态, id={}, status={}", ro.getFeedbackId(), ro.getStatus());
        FeedbackEntity entity = feedbackMapper.selectById(ro.getFeedbackId());
        if (entity == null) {
            log.warn("[lbl][2087-消息推送][Feedback][UPDATE] 反馈记录不存在, id={}", ro.getFeedbackId());
            throw new BusinessException("反馈记录不存在");
        }
        entity.setStatus(ro.getStatus());
        feedbackMapper.updateById(entity);
        log.info("[lbl][2087-消息推送][Feedback][UPDATE] 更新反馈状态成功, id={}, status={}", ro.getFeedbackId(), ro.getStatus());
    }

    /**
     * 上传前端附件到MinIO
     */
    private List<String> uploadFilesToMinio(List<MultipartFile> files) {
        List<String> urls = new ArrayList<>();
        if (files == null || files.isEmpty()) {
            return urls;
        }
        String bucketName = constProperties.getOssBucketByAsset().getBucketName();
        for (MultipartFile file : files) {
            try {
                String keyPath = "feedback/" + LocalDate.now().format(DateTimeFormatter.BASIC_ISO_DATE)
                        + "/" + UUID.randomUUID() + "_" + file.getOriginalFilename();
                ossTemplate.upload(bucketName, file.getInputStream(), keyPath);
                String url = constProperties.getOssBucketByAsset().getResourceUrl() + "/" + keyPath;
                urls.add(url);
            } catch (IOException e) {
                log.error("[lbl][2087-消息推送][Feedback][UPLOAD] 附件上传MinIO失败, fileName={}, error={}", file.getOriginalFilename(), e.getMessage(), e);
            }
        }
        return urls;
    }

    /**
     * 从MM下载附件并上传到MinIO
     */
    private List<String> downloadMmFilesAndUpload(List<String> fileIds) {
        List<String> urls = new ArrayList<>();
        if (fileIds == null || fileIds.isEmpty()) {
            return urls;
        }
        String bucketName = constProperties.getOssBucketByAsset().getBucketName();
        String authToken = "Bearer " + mattermostProperties.getXcollabspaceBotToken();

        for (String fileId : fileIds) {
            try {
                log.info("[lbl][2087-消息推送][Feedback][DOWNLOAD] 调用MM Feign下载附件, fileId={}", fileId);
                byte[] fileData = mattermostMessageFeign.downloadFile(authToken, fileId);
                log.info("[lbl][2087-消息推送][Feedback][DOWNLOAD] MM附件下载完成, fileId={}, fileSize={}bytes", fileId, fileData.length);
                String keyPath = "feedback/mm/" + LocalDate.now().format(DateTimeFormatter.BASIC_ISO_DATE)
                        + "/" + UUID.randomUUID() + "_" + fileId;
                ossTemplate.upload(bucketName, new ByteArrayInputStream(fileData), keyPath);
                String url = constProperties.getOssBucketByAsset().getResourceUrl() + "/" + keyPath;
                urls.add(url);
                log.info("[lbl][2087-消息推送][Feedback][UPLOAD] MM附件上传MinIO成功, fileId={}, keyPath={}", fileId, keyPath);
            } catch (Exception e) {
                log.error("[lbl][2087-消息推送][Feedback][UPLOAD] MM附件下载上传失败, fileId={}, error={}", fileId, e.getMessage(), e);
            }
        }
        return urls;
    }

    private FeedbackVo toVo(FeedbackEntity entity) {
        FeedbackVo vo = new FeedbackVo();
        vo.setId(entity.getId());
        vo.setUserId(entity.getUserId());
        vo.setUserName(entity.getUserName());
        vo.setFeedbackTime(entity.getFeedbackTime());
        vo.setDocType(entity.getDocType());
        vo.setFeedbackType(entity.getFeedbackType());
        vo.setRelatedLink(entity.getRelatedLink());
        vo.setContent(entity.getContent());
        vo.setAttachments(StrUtil.isNotBlank(entity.getAttachments())
                ? JSONUtil.toList(entity.getAttachments(), String.class)
                : List.of());
        vo.setExtraInfo(entity.getExtraInfo());
        vo.setSource(entity.getSource());
        vo.setStatus(entity.getStatus());
        return vo;
    }
}

