package com.apitable.player.controller;

import com.apitable.core.exception.BusinessException;
import com.apitable.core.support.ResponseData;
import com.apitable.player.ro.NotificationCreateRo;
import com.apitable.player.ro.NotificationListRo;
import com.apitable.player.ro.NotificationOutlineRo;
import com.apitable.player.ro.NotificationPageRo;
import com.apitable.player.ro.NotificationReadRo;
import com.apitable.player.service.IPermissionRequestService;
import com.apitable.player.service.IPlayerNotificationService;
import com.apitable.player.vo.NotificationDetailVo;
import com.apitable.player.vo.NotificationStatisticsVo;
import com.apitable.shared.component.scanner.annotation.ApiResource;
import com.apitable.shared.component.scanner.annotation.GetResource;
import com.apitable.shared.component.scanner.annotation.PostResource;
import com.apitable.shared.constants.PageConstants;
import com.apitable.shared.context.LoginContext;
import com.apitable.shared.context.SessionContext;
import com.google.common.collect.Lists;

import cn.hutool.json.JSONObject;
import cn.hutool.json.JSONUtil;
import io.swagger.v3.oas.annotations.Operation;
import io.swagger.v3.oas.annotations.tags.Tag;
import java.util.List;
import java.util.Objects;

import jakarta.annotation.Resource;
import jakarta.validation.Valid;
import lombok.extern.slf4j.Slf4j;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RestController;

import java.util.HashMap;
import java.util.Map;

/**
 * Player System - Notification API.
 */
@Slf4j
@RestController
@Tag(name = "Player System - Notification API")
@ApiResource(path = "/player/notification")
public class NotificationController {

    @Resource
    private IPlayerNotificationService playerNotificationService;

    @Resource
    private IPermissionRequestService permissionRequestService;

    /**
     * Get Notification Page Info.
     */
    @GetResource(path = "/page", requiredPermission = false)
    @Operation(summary = "Get Notification Page Info", description = PageConstants.PAGE_DESC)
    public ResponseData<List<NotificationDetailVo>> page(
        @Valid NotificationPageRo notificationPageRo) {
        List<NotificationDetailVo> pageInfo =
            playerNotificationService.pageList(notificationPageRo,
                LoginContext.me().getLoginUser());
        return ResponseData.success(pageInfo);
    }

    /**
     * Mark Notification Rea.
     */
    @PostResource(path = "/read", requiredPermission = false)
    @Operation(summary = "Mark Notification Read")
    public ResponseData<Boolean> read(@RequestBody NotificationReadRo notificationReadRo) {
        return ResponseData.success(
            playerNotificationService.setNotificationIsRead(notificationReadRo.getId(),
                notificationReadRo.getIsAll()));
    }

    /**
     * Delete Notification.
     */
    @PostResource(path = "/delete", requiredPermission = false)
    @Operation(summary = "Delete Notification")
    public ResponseData<Boolean> delete(@RequestBody NotificationReadRo notificationReadRo) {
        return ResponseData.success(
            playerNotificationService.setDeletedIsTrue(notificationReadRo.getId()));
    }

    /**
     * Create Notification.
     */
    @PostResource(path = "/create", requiredPermission = false)
    @Operation(summary = "Create Notification")
    public ResponseData<Void> create(
        @Valid @RequestBody List<NotificationCreateRo> notificationCreateRoList) {
        boolean bool = playerNotificationService.batchCreateNotify(notificationCreateRoList);
        if (bool) {
            return ResponseData.success();
        } else {
            throw new BusinessException("insert error");
        }
    }

    /**
     * Get Notification' Statistics.
     */
    @GetResource(path = "/statistics", requiredPermission = false)
    @Operation(summary = "Get Notification' Statistics")
    public ResponseData<NotificationStatisticsVo> statistics() {
        return ResponseData.success(
            playerNotificationService.statistic(SessionContext.getUserId()));
    }

    /**
     * Get Notification Detail List.
     */
    @GetResource(path = "/list", requiredPermission = false)
    @Operation(summary = "Get Notification Detail List", description = "Default: System "
        + "Notification")
    public ResponseData<List<NotificationDetailVo>> list(
        @Valid NotificationListRo notificationListRo) {
        return ResponseData.success(
            playerNotificationService.list(notificationListRo, LoginContext.me().getLoginUser()));
    }

    /**
     * Approve permission request.
     */
    @PostResource(path = "/{notificationId}/approve", requiredPermission = false)
    @Operation(summary = "Approve permission request")
    public ResponseData<Void> approve(@PathVariable("notificationId") Long notificationId) {
        Long userId = SessionContext.getUserId();
        log.info("[1822-Approval] APPROVE entry notificationId={} approverUserId={}", notificationId, userId);
        permissionRequestService.approve(notificationId, userId);
        return ResponseData.success();
    }

    /**
     * Reject permission request.
     */
    @PostResource(path = "/{notificationId}/reject", requiredPermission = false)
    @Operation(summary = "Reject permission request")
    public ResponseData<Void> reject(@PathVariable("notificationId") Long notificationId) {
        Long userId = SessionContext.getUserId();
        log.info("[1822-Approval] REJECT entry notificationId={} approverUserId={}", notificationId, userId);
        permissionRequestService.reject(notificationId, userId);
        return ResponseData.success();
    }

    /**
     * Ignore permission request (mark as read for this admin).
     */
    @PostResource(path = "/{notificationId}/ignore", requiredPermission = false)
    @Operation(summary = "Ignore permission request")
    public ResponseData<Void> ignore(@PathVariable("notificationId") Long notificationId) {
        Long userId = SessionContext.getUserId();
        log.info("[1822-Approval] IGNORE entry notificationId={} approverUserId={}", notificationId, userId);
        permissionRequestService.ignore(notificationId, userId);
        return ResponseData.success();
    }

    /**
     * Reapprove - un-ignore to handle again.
     */
    @PostResource(path = "/{notificationId}/reapprove", requiredPermission = false)
    @Operation(summary = "Reapprove (un-ignore) permission request")
    public ResponseData<Void> reapprove(@PathVariable("notificationId") Long notificationId) {
        Long userId = SessionContext.getUserId();
        log.info("[1822-Approval] REAPPROVE entry notificationId={} approverUserId={}", notificationId, userId);
        permissionRequestService.reapprove(notificationId, userId);
        return ResponseData.success();
    }

    /**
     * Ignore all unhandled approval notifications (one-click ignore in approval tab)
     */
    @PostResource(path = "/approval/ignoreAllUnhandled", requiredPermission = false)
    @Operation(summary = "Ignore all unhandled approval notifications")
    public ResponseData<Map<String, Object>> ignoreAllApprovalUnhandled() {
        Long userId = SessionContext.getUserId();
        log.info("[1822-Approval] IGNORE_ALL entry approverUserId={}", userId);
        int count = playerNotificationService.ignoreAllApprovalUnhandled(userId);
        Map<String, Object> data = new HashMap<>();
        data.put("count", count);
        return ResponseData.success(data);
    }

    @PostResource(path = "/outline", requiredPermission = false)
    @Operation(summary = "outline Notification")
    public ResponseData<Void> outlineRemind(
        @Valid @RequestBody NotificationOutlineRo notificationOutlineRo) {
        NotificationCreateRo notificationCreateRo = new NotificationCreateRo();
        notificationCreateRo.setSendKnockNotification(notificationOutlineRo.getSendKnockNotification());
        notificationCreateRo.setTemplateId("outline_comment_mentioned");
        notificationCreateRo.setNodeId(notificationOutlineRo.getNodeId());
        notificationCreateRo.setSpaceId(notificationOutlineRo.getSpaceId());
        notificationCreateRo.setToUserId(Lists.newArrayList(notificationOutlineRo.getToUserId()));

        JSONObject body = JSONUtil.createObj();
        body.set("text", notificationOutlineRo.getText());
        body.set("docId", notificationOutlineRo.getDocId());
        body.set("toUserName", notificationOutlineRo.getToUserName());
        // 克隆一份放在 extras 中，该 extras 会被前端使用，内部 docId 会用于生成 Outline 跳转链接
        body.set("extras", new JSONObject(body));
        notificationCreateRo.setBody(body);

        Long userId = SessionContext.getUserIdWithoutException();
        if (userId != null && Objects.equals(notificationCreateRo.getFromUserId(), "0")) {
            notificationCreateRo.setFromUserId(userId.toString());
        }

        try {
            playerNotificationService.createNotify(notificationCreateRo);
            return ResponseData.success();
        } catch (Exception e) {
            log.error("Outline @通知失败：", e);
            return ResponseData.error();
        }
    }
}

