package com.apitable.thrid.service.impl;

import cn.hutool.json.JSONObject;
import cn.hutool.json.JSONUtil;
import com.apitable.organization.service.IUnitService;
import com.apitable.shared.config.properties.KnockProperties;
import com.apitable.thrid.feign.OAChnService;
import com.apitable.thrid.req.OAChnSendRequest;
import com.apitable.thrid.service.KnockMessageService;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;

import jakarta.annotation.PostConstruct;
import jakarta.annotation.Resource;
import java.util.*;

import static org.apache.commons.compress.utils.ArchiveUtils.sanitize;

@Service
@Slf4j
public class KnockMessageServiceImpl implements KnockMessageService {

    private static final String SIGN_KEY = "knock_send_robot_msg";
    private static final String GROUP_SIGN_KEY = "knock_send_grt_msg";

    @Resource
    private KnockProperties knockProperties;

    @Resource
    private OAChnService oaChnService;

    @Resource
    private IUnitService unitService;

    @Value("${oa.chn.client-id}")
    private String clientId;

    @Value("${oa.chn.client-secret}")
    private String clientSecret;

    @Value("${pipeline.procedure-grt-mapping}")
    private String grtMappingJson;

    private Map<String, String> procedureGrtMap;

    @PostConstruct
    private void init() {
        procedureGrtMap = new HashMap<>();
        JSONObject grtJsonObject = JSONUtil.parseObj(grtMappingJson);
        for (Map.Entry<String, Object> entry : grtJsonObject.entrySet()) {
            String key = sanitize(entry.getKey());
            String value = (String) entry.getValue();
            procedureGrtMap.put(key, value);
        }
    }

    @Override
    public void sendKnockMessage(Collection<String> nicknames, String msg) {
        log.info("sendKnockMessage-1: {} {}", nicknames, msg);
        String payload = buildPayload(nicknames, msg);
        String sign = generateSign(payload, SIGN_KEY);
        OAChnSendRequest request = buildRequest(payload, sign, SIGN_KEY);
        sendRequest(request);
    }

    @Override
    public void sendKnockGroupMessage(Collection<String> nicknames, String content, String grtToken) {
        String payload = buildGroupPayload(nicknames, content, grtToken);
        String sign = generateSign(payload, GROUP_SIGN_KEY);
        OAChnSendRequest request = buildRequest(payload, sign, GROUP_SIGN_KEY);
        sendRequest(request);
    }

    private String buildGroupPayload(Collection<String> nicknames, String content, String grtToken) {
        Map<String, Object> body = new HashMap<>();
        body.put("nicknames", nicknames);
        body.put("group_robot_token", grtToken);
        body.put("content", content);
        return JSONUtil.toJsonStr(body);
    }

    @Override
    public void sendKnockMessageByUnitIds(Collection<Long> unitIds, String content) {
        List<String> nicknames = unitService.getNicknamesByUnitIds(unitIds);
        sendKnockMessage(nicknames, content);
    }

    @Override
    public void sendKnockGroupMessageByUnitIds(List<Long> unitIds, String content, String procedure) {
        List<String> nicknames = unitService.getNicknamesByUnitIds(unitIds);
        String grtToken = getGrtTokenByProcedure(procedure);
        if (grtToken == null) {
            return;
        }
        sendKnockGroupMessage(nicknames, content, grtToken);
    }

    private String getGrtTokenByProcedure(String procedure) {
        String sanitizedProcedure = sanitize(procedure);
        String grtToken = procedureGrtMap.get(sanitizedProcedure);
        if (grtToken == null) {
            log.warn("No GRT token found for procedure: {}", sanitizedProcedure);
        }
        return grtToken;
    }

    private String buildPayload(Collection<String> nicknames, String content) {
        Map<String, Object> body = new HashMap<>();
        body.put("nicknames", nicknames);
        body.put("robot_name", knockProperties.getNotification1());
        body.put("content", content);
        return JSONUtil.toJsonStr(body);
    }

    private String generateSign(String payload, String signKey) {
        return oaChnService.getSign(clientId, signKey, payload, clientSecret);
    }

    private OAChnSendRequest buildRequest(String payload, String sign, String signKey) {
        OAChnSendRequest request = new OAChnSendRequest();
        request.setKey(signKey);
        request.setClientId(clientId);
        request.setSign(sign);
        request.setPayload(payload);
        return request;
    }

    private void sendRequest(OAChnSendRequest request) {
        log.info("Sending Knock message request: {}", JSONUtil.toJsonStr(request));
        Object result = oaChnService.send(request);
        log.info("Knock message response: {}", JSONUtil.toJsonStr(result));
    }
}

