package com.apitable.thrid.feign;

import com.apitable.thrid.req.OAChnSendRequest;
import java.util.Comparator;
import java.util.Map;
import java.util.TreeMap;
import org.springframework.cloud.openfeign.FeignClient;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import cn.hutool.crypto.digest.DigestUtil;

@FeignClient(name = "oaChnService", url = "${oa.chn.host}")
public interface OAChnService {

    @PostMapping("/third-api/request")
    Object send(@RequestBody OAChnSendRequest oaChnSendRequest);

    default String getSign(String clientId, String key, String payload, String clientSecret) {
        Map<String, String> map = new TreeMap<>(new Comparator<String>() {
            public int compare(String key1, String key2) {
                return key1.compareTo(key2);
            }
        });
        map.put("api_secret", clientSecret);
        map.put("client_id", clientId);
        map.put("key", key);
        map.put("payload", payload);
        final StringBuilder res = new StringBuilder();
        map.forEach((k, v) -> {
            res.append(k).append("=").append(v).append("&");
        });
        res.deleteCharAt(res.length() - 1);
        return DigestUtil.md5Hex(res.toString());
    }
}

