import static com.sanluan.einvoice.util.KnockUtil.sendRobotRichMsg;

/**
 * @author luobeilin
 */
@Slf4j
@Component
public class AddExpatMemberJob {
    public static final String ALL_EXPAT_USER = "https://apitable.yottastudios.com/api/v1/org/member/allExpatUser";
    public static final String NAME_NOTE = "小兰";
    // 以下为 新增外派成员 定时任务所需参数
    private static final String API_TABLE_HOST = "https://apitable.yottastudios.com";
    private static final String API_TABLE_TOKEN = "uskgxMiEjrx8zmi0wujBHNH";
    private static final String DATASHEET_ID = "dstMpWBTlY46";
    private static final String VIEW_ID = "viwJoVhggQpH";
    // 以下为群通知所需参数
    private static final String APITABLE = "apitable";
    private static final String CLIENT_SECRET = "0977ad6723022fbebd8d5566140f5c14";
    private static final String SEND_KNOCK_URL = "https://oa-chn.xinyoudi.com/third-api/request";

    public static void main(String[] args) {
        projectD();
    }

    public static void projectD() {
        String startTime = now();
        try {
            doExpat();
        } catch (Exception e) {
            log.error("新增外派成员 定时任务执行失败：" + end(startTime) + "error=" + e.getMessage(), e);
        }
        log.info("新增外派成员 定时任务执行完毕" + end(startTime));
    }


    private static void doExpat() {


        List<SpaceMember> oldSpaceMembers = oldData();

        List<SpaceMember> newSpaceMembers = newData();

        List<SpaceMember> addSpaceMembers = newSpaceMembers.stream().filter(newSpaceMember -> notInList(oldSpaceMembers, newSpaceMember)).collect(Collectors.toList());

        List<SpaceMember> removeSpaceMembers = oldSpaceMembers.stream().filter(oldSpaceMember -> notInList(newSpaceMembers, oldSpaceMember)).collect(Collectors.toList());


        String title = "【外派成员+空间站】变动" + "\n";
        StringBuilder content = new StringBuilder();
        addSpaceMembers.forEach(spaceMember -> content.append("【")
            .append(spaceMember.getMemberName()).append("】 加入了 【")
            .append(spaceMember.getSpaceName()).append("】空间站\n"));

        removeSpaceMembers.forEach(spaceMember -> content.append("【")
            .append(spaceMember.getMemberName()).append("】 离开了 【")
            .append(spaceMember.getSpaceName()).append("】空间站\n"));

        List<SpaceMember> updateSpaceMembers = getUpdateSpaceMembers(oldSpaceMembers, newSpaceMembers);
        if (updateSpaceMembers.size() > 0) {
            updateRecords(updateSpaceMembers);
        }

        if (addSpaceMembers.size() == 0 && removeSpaceMembers.size() == 0) {
            return;
        }

        if (addSpaceMembers.size() > 0) {
            addRecords(addSpaceMembers);
        }
        if (removeSpaceMembers.size() > 0) {
            removeRecords(removeSpaceMembers);
        }

        KnockUtil.KnockConfig knockConfig = new KnockUtil.KnockConfig(APITABLE, CLIENT_SECRET);
        KnockUtil.Knock groupKnock = new KnockUtil.Knock(knockConfig, KnockUtil.MsgType.ROBOT.value(),
            KnockUtil.Robot.YOTTA_TABLE.value());

        List<String> nicknames = new ArrayList<>();
        nicknames.add(NAME_NOTE);
        sendRobotRichMsg(SEND_KNOCK_URL, groupKnock, nicknames, title, content.toString());
    }

    private static List<SpaceMember> getUpdateSpaceMembers(List<SpaceMember> oldSpaceMembers, List<SpaceMember> newSpaceMembers) {
        List<SpaceMember> updateSpaceMembers = new ArrayList<>();
        for (SpaceMember newSpaceMember : newSpaceMembers) {
            for (SpaceMember oldSpaceMember : oldSpaceMembers) {
                if (newSpaceMember.getMemberName().equals(oldSpaceMember.getMemberName())
                    && newSpaceMember.getSpaceName().equals(oldSpaceMember.getSpaceName())
                    && newSpaceMember.getAccount().equals(oldSpaceMember.getAccount())) {
                    if (!newSpaceMember.getSpaceManager().equals(oldSpaceMember.getSpaceManager())) {
                        newSpaceMember.setRecordId(oldSpaceMember.getRecordId());
                        updateSpaceMembers.add(newSpaceMember);
                    }
                    break;
                }
            }
        }
        return updateSpaceMembers;
    }

    private static List<SpaceMember> newData() {
//        log.info("拉取数据中..." + ALL_EXPAT_USER);
        String startTime = now();
        String s = HttpUtil.get(ALL_EXPAT_USER);
        JSONObject entries = JSONUtil.parseObj(s);
        JSONArray data = entries.getJSONArray("data");
        List<SpaceMember> list = data.toList(SpaceMember.class);
        log.info("拉取newData数据成功：" + list.size() + " " + ALL_EXPAT_USER + " " + end(startTime));
        return list;
    }

    private static boolean notInList(List<SpaceMember> spaceMembers, SpaceMember spaceMember) {
        for (SpaceMember spaceMember1 : spaceMembers) {
            if (spaceMember1.getMemberName().equals(spaceMember.getMemberName())
                && spaceMember1.getSpaceName().equals(spaceMember.getSpaceName())
                && spaceMember1.getAccount().equals(spaceMember.getAccount())) {
                return false;
            }
        }
        return true;
    }

    private static List<SpaceMember> oldData() {
        List<SpaceMember> oldSpaceMembers = new ArrayList<>();
        List<Record> records = AddExpatMemberJob.getRecords();
        for (Record record : records) {
            SpaceMember spaceMember = new SpaceMember();

            Object nick = record.getFields().get("昵称");
            if (nick == null) {
                continue;
            }
            spaceMember.setMemberName(nick.toString());

            Object spaceName = record.getFields().get("空间站名称");
            spaceMember.setSpaceName(spaceName.toString());

            Object spaceManager = record.getFields().get("空间站管理员");
            if (spaceManager != null) {
                spaceMember.setSpaceManager(spaceManager.toString());
            }

            Object account = record.getFields().get("账号");
            spaceMember.setAccount(account.toString());

            String recordId = record.getRecordId();
            spaceMember.setRecordId(recordId);

            oldSpaceMembers.add(spaceMember);
        }
        return oldSpaceMembers;
    }

    private static List<Record> getRecords() {
        try {
            ApiCredential credential = new ApiCredential(API_TABLE_TOKEN);
            ApitableApiClient apitableApiClient = new ApitableApiClient(API_TABLE_HOST, credential);
            ApiQueryParam queryParam = new ApiQueryParam(1, 500)
                .withView(VIEW_ID);
            String startTime = now();
            Pager<Record> records = apitableApiClient.getRecordApi().getRecords(DATASHEET_ID, queryParam);
            log.info("拉取getRecords数据：" + +records.all().size()+ " " + DATASHEET_ID + " " + queryParam + end(startTime));
            return records.all();
        } catch (Exception e) {
            log.info("拉取数据失败：" + e.getMessage());
            throw new RuntimeException(e);
        }
    }

    private static String now() {
        return DateUtil.format(LocalDateTime.now(), "yyyy-MM-dd HH:mm:ss.SSSSSS");
    }

    private static String end(String startTime) {
        return " startTime=" + startTime + " endTime=" + now();
    }

    private static void addRecords(List<SpaceMember> spaceMembers) {

        // 超过10个， 10个一次
        int size = spaceMembers.size();
        int count = size / 10;
        if (size % 10 != 0) {
            count++;
        }
        for (int i = 0; i < count; i++) {
            int start = i * 10;
            int end = start + 10;
            if (end > size) {
                end = size;
            }
            List<SpaceMember> subList = spaceMembers.subList(start, end);
            doAddRecords(subList);
        }
    }

    private static void updateRecords(List<SpaceMember> spaceMembers) {

        // 超过10个， 10个一次
        int size = spaceMembers.size();
        int count = size / 10;
        if (size % 10 != 0) {
            count++;
        }
        for (int i = 0; i < count; i++) {
            int start = i * 10;
            int end = start + 10;
            if (end > size) {
                end = size;
            }
            List<SpaceMember> subList = spaceMembers.subList(start, end);
            doUpdateRecords(subList);
        }
    }

    private static void removeRecords(List<SpaceMember> spaceMembers) {

        // 超过10个， 10个一次
        int size = spaceMembers.size();
        int count = size / 10;
        if (size % 10 != 0) {
            count++;
        }
        for (int i = 0; i < count; i++) {
            int start = i * 10;
            int end = start + 10;
            if (end > size) {
                end = size;
            }
            List<SpaceMember> subList = spaceMembers.subList(start, end);
            doRemoveRecords(subList);
        }
    }

    private static void doAddRecords(List<SpaceMember> spaceMembers) {
        try {
            ApiCredential credential = new ApiCredential(API_TABLE_TOKEN);
            ApitableApiClient apitableApiClient = new ApitableApiClient(API_TABLE_HOST, credential);

            log.info("新增数据中..." + DATASHEET_ID + " " + spaceMembers);
            ArrayNode jsonNodes = JsonNodeFactory.instance.arrayNode();
            for (SpaceMember spaceMember : spaceMembers) {
                ObjectNode fieldMap = JsonNodeFactory.instance.objectNode()
                    .put("昵称", spaceMember.getMemberName())
                    .put("空间站名称", spaceMember.getSpaceName())
                    .put("空间站管理员", spaceMember.getSpaceManager())
                    .put("账号", spaceMember.getAccount());
                ObjectNode fields = JsonNodeFactory.instance.objectNode().set("fields", fieldMap);
                jsonNodes.add(fields);
            }
            List<RecordMap> recordMaps = JacksonConverter.unmarshalToList(RecordMap.class, jsonNodes);
            CreateRecordRequest recordRequest = new CreateRecordRequest().withRecords(recordMaps);
            RecordApi recordApi = apitableApiClient.getRecordApi();
            recordApi.addRecords(DATASHEET_ID, recordRequest);
        } catch (Exception e) {
            log.error("新增数据失败：", e);
        }
    }

    private static void doUpdateRecords(List<SpaceMember> spaceMembers) {
        try {
            ApiCredential credential = new ApiCredential(API_TABLE_TOKEN);
            ApitableApiClient apitableApiClient = new ApitableApiClient(API_TABLE_HOST, credential);

            log.info("更新数据中..." + DATASHEET_ID + " " + spaceMembers);
            List<UpdateRecord> records = new ArrayList<>();
            for (SpaceMember spaceMember : spaceMembers) {
                UpdateRecord record = new UpdateRecord()
                    .withRecordId(spaceMember.getRecordId())
                    .withField("空间站管理员", spaceMember.getSpaceManager());
                records.add(record);
            }
            UpdateRecordRequest updateRecordRequest = new UpdateRecordRequest()
                .withRecords(records);
            apitableApiClient.getRecordApi().updateRecords(DATASHEET_ID, updateRecordRequest);
        } catch (Exception e) {
            log.error("更新数据失败：", e);
        }
    }

    private static void doRemoveRecords(List<SpaceMember> spaceMembers) {
        try {
            ApiCredential credential = new ApiCredential(API_TABLE_TOKEN);
            ApitableApiClient apitableApiClient = new ApitableApiClient(API_TABLE_HOST, credential);

            log.info("删除数据中..." + DATASHEET_ID + " " + spaceMembers);
            List<String> recordIds = spaceMembers.stream().map(SpaceMember::getRecordId).collect(Collectors.toList());
            apitableApiClient.getRecordApi().deleteRecords(DATASHEET_ID, recordIds);
        } catch (Exception e) {
            log.error("删除数据失败：", e);
        }
    }

    @Scheduled(cron = "0 0/10 * * * ?")
    public void handle() {
        projectD();
    }

    @Data
    public static class SpaceMember {
        private String memberName;
        private String spaceName;
        private String spaceManager;
        private String account;
        private String recordId;
    }
}

