package com.sanluan.einvoice.util;

import cn.hutool.core.date.DateUtil;
import cn.hutool.crypto.digest.DigestUtil;
import cn.hutool.json.JSONUtil;
import com.google.common.collect.Lists;
import lombok.AllArgsConstructor;
import lombok.Builder;
import lombok.Data;
import lombok.NoArgsConstructor;
import org.springframework.http.HttpEntity;
import org.springframework.http.HttpHeaders;
import org.springframework.http.MediaType;
import org.springframework.web.client.RestTemplate;

import java.util.*;

public class KnockUtil {

    public static void main(String[] args) {
        String sendKnockUrl = "http://oa-chn.xinyoudi.com/third-api/request";
        KnockConfig knockConfig = new KnockConfig("apitable", "0977ad6723022fbebd8d5566140f5c14");

        List<String> nickName = Lists.newArrayList("罗贝林");
        String title = "标题" + DateUtil.now();
        String content = "hello world @罗贝林 " + DateUtil.now();

        Knock robotKnock = new Knock(knockConfig, MsgType.ROBOT.value(), Robot.OA_TEST.value());
        sendRobotRichMsg(sendKnockUrl, robotKnock, nickName, title, content);
        sendRobotMsg(sendKnockUrl, robotKnock, nickName, content);

        Knock groupKnock = new Knock(knockConfig, MsgType.GRT.value(), "GRT:97aEBC04OFz8");
        sendGroupRichMsg(sendKnockUrl, groupKnock, nickName, title, content);
        sendGroupMsg(sendKnockUrl, groupKnock, nickName, content);

    }

    public static void sendGroupMsg(String sendKnockUrl, Knock groupKnock, List<String> nickName, String content) {
        Map<String, Object> groupBody = getGroupBody(groupKnock.getRobotName(), nickName, content);
        sendHttp(groupKnock, sendKnockUrl, groupBody);
    }

    public static void sendGroupRichMsg(String sendKnockUrl, Knock groupKnock, List<String> nickName, String title,
                                   String content) {
        Map<String, Object> groupRichBody = getGroupRichBody(groupKnock.getRobotName(), nickName, title, content);
        sendHttp(groupKnock, sendKnockUrl, groupRichBody);
    }

    public static void sendRobotMsg(String sendKnockUrl, Knock robotKnock, List<String> nickName, String content) {
        Map<String, Object> robotBody = getRobotBody(robotKnock.getRobotName(), nickName, content);
        sendHttp(robotKnock, sendKnockUrl, robotBody);
    }

    public static void sendRobotRichMsg(String sendKnockUrl, Knock robotKnock, List<String> nickName, String title, String content) {
        Map<String, Object> robotRichBody = getRobotRichBody(robotKnock.getRobotName(), nickName, title, content);
        sendHttp(robotKnock, sendKnockUrl, robotRichBody);
    }

    /**
     * 获取富文本消息体
     */
    private static Map<String, Object> getRobotRichBody(String robotName, List<String> nickName, String title, String content) {
        Map<String, Object> body = getRichBody(nickName, title, content);
        body.put("robot_name", robotName);
        return body;
    }

    /**
     * 获取富文本消息体
     */
    private static Map<String, Object> getGroupRichBody(String robotName, List<String> nickName, String title, String content) {
        Map<String, Object> body = getRichBody(nickName, title, content);
        body.put("group_robot_token", robotName);
        return body;
    }

    /**
     * 获取消息体
     */
    private static Map<String, Object> getRobotBody(String robotName, List<String> nickName, String content) {
        Map<String, Object> body = getBody(nickName, content);
        body.put("robot_name", robotName);
        return body;
    }

    /**
     * 获取消息体
     */
    private static Map<String, Object> getGroupBody(String robotName, List<String> nickName, String content) {
        Map<String, Object> body = getBody(nickName, content);
        body.put("group_robot_token", robotName);
        return body;
    }

    private static Map<String, Object> getRichBody(List<String> nickName, String title, String content) {
        Map<String, Object> body = getBase(nickName);
        Content m = new Content(title, content);
        body.put("content", JSONUtil.toJsonStr(m));
        body.put("msg_type", "MSG_TYPE_RICH_CARD");
        return body;
    }

    private static Map<String, Object> getBody(List<String> nickName, String content) {
        Map<String, Object> body = getBase(nickName);
        body.put("content", content);
        body.put("msg_type", "TEXT");
        return body;
    }

    private static Map<String, Object> getBase(List<String> nicknames) {
        Map<String, Object> body = new HashMap<>();
        body.put("nicknames", nicknames);
        return body;
    }

    private static void sendHttp(Knock knock, String sendKnockUrl, Map<String, Object> body) {
        String jsonBody = JSONUtil.toJsonStr(body);
        String sign = getSigns(knock, jsonBody);
        Req req = new Req(knock.getKnockConfig().getClientId(), knock.getMsgType(), jsonBody, sign);
        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.APPLICATION_JSON);
        HttpEntity<Object> entity = new HttpEntity<>(JSONUtil.toJsonStr(req), headers);
        RestTemplate restTemplate = new RestTemplate();
        String s = restTemplate.postForObject(sendKnockUrl, entity, String.class);
        System.out.println(s);
    }


    private static String getSigns(Knock knock, String jsonBody) {
        Map<String, String> map = new TreeMap<>(Comparator.naturalOrder());
        map.put("api_secret", knock.getKnockConfig().getClientSecret());
        map.put("client_id", knock.getKnockConfig().getClientId());
        map.put("key", knock.getMsgType());
        map.put("payload", jsonBody);
        final StringBuilder res = new StringBuilder();
        map.forEach((k, v) -> {
            res.append(k).append("=").append(v).append("&");
        });
        res.deleteCharAt(res.length() - 1);
        return DigestUtil.md5Hex(res.toString());
    }

    @Data
    @AllArgsConstructor
    @NoArgsConstructor
    static class Content {
        private String title;
        private String content;
    }

    @Data
    @AllArgsConstructor
    @NoArgsConstructor
    public static class Knock {
        private KnockConfig knockConfig;
        private String msgType;
        private String robotName;
    }

    @Data
    @AllArgsConstructor
    @NoArgsConstructor
    public static class KnockConfig {
        private String clientId;
        private String clientSecret;
    }

    @Data
    @NoArgsConstructor
    @AllArgsConstructor
    @Builder
    static class Req {
        private String client_id;
        private String key;
        private String payload;
        private String sign;
    }

    public enum MsgType {
        ROBOT("knock_send_robot_msg"),
        GRT("knock_send_grt_msg");

        private String value;

        MsgType(String value) {
            this.value = value;
        }

        public String value() {
            return this.value;
        }
    }
    public enum Robot {
        YOTTA_TABLE("yotta-Yottatable"),
        OA_TEST("yotta-oa-test");

        private String value;

        Robot(String value) {
            this.value = value;
        }

        public String value() {
            return this.value;
        }
    }

}

