package com.yottastudios.ns.collabspace.announcement.service.impl;

import com.yottastudios.ns.collabspace.announcement.entity.AnnouncementEntity;
import com.yottastudios.ns.collabspace.announcement.mapper.AnnouncementMapper;
import com.yottastudios.ns.collabspace.announcement.util.AnnouncementFormatConverter;
import com.yottastudios.ns.collabspace.shared.config.properties.MattermostProperties;
import com.yottastudios.ns.collabspace.shared.config.properties.SystemProperties;
import com.yottastudios.ns.collabspace.third.feign.MattermostMessageFeign;
import com.yottastudios.ns.collabspace.third.req.MattermostPostReq;
import com.yottastudios.ns.collabspace.third.service.KnockService;
import jakarta.annotation.Resource;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;

import java.util.List;

/**
 * 公告发布后同步推送到 Knock 和 MM
 */
@Slf4j
@Service
public class AnnouncementPushService {

    @Resource
    private KnockService knockService;

    @Resource
    private AnnouncementMapper announcementMapper;

    @Resource
    private MattermostMessageFeign mattermostMessageFeign;

    @Resource
    private MattermostProperties mattermostProperties;

    @Resource
    private SystemProperties systemProperties;

    /**
     * 公告发布后推送到 Knock + MM
     */
    public void pushAnnouncement(AnnouncementEntity announcement) {
        log.info("[lbl][2087-消息推送][Announcement][PUSH] 开始推送公告到Knock+MM, id={}, title={}", announcement.getId(), announcement.getTitle());

        pushToKnock(announcement);
        pushToMm(announcement);

        log.info("[lbl][2087-消息推送][Announcement][PUSH] 公告推送完成, id={}", announcement.getId());
    }

    /**
     * 推送到 Knock（通过 Yottatable 机器人发送富文本消息给所有用户）
     */
    private void pushToKnock(AnnouncementEntity announcement) {
        try {
            String knockContent = AnnouncementFormatConverter.toKnockMarkdown(announcement.getContent());
            String title = announcement.getTitle();

            // 查询所有用户昵称
            List<String> allNickNames = announcementMapper.selectAllUserNickNames();
            log.info("[lbl][2087-消息推送][Announcement][PUSH] Knock推送准备, id={}, nicknameCount={}, titleLength={}, contentLength={}",
                    announcement.getId(), allNickNames.size(), title.length(), knockContent.length());

            if (allNickNames.isEmpty()) {
                log.warn("[lbl][2087-消息推送][Announcement][PUSH] 无用户昵称, 跳过Knock推送, id={}", announcement.getId());
                return;
            }

            // 测试环境只打日志不发送
            if (systemProperties.isTestEnabled()) {
                log.info("[lbl][2087-消息推送][Announcement][PUSH] [测试环境-不发送] Knock推送, id={}, title={}, nicknameCount={}",
                        announcement.getId(), title, allNickNames.size());
                return;
            }

            knockService.sendRobotRichMsg(allNickNames, title, knockContent);
            log.info("[lbl][2087-消息推送][Announcement][PUSH] Knock推送成功, id={}", announcement.getId());
        } catch (Exception e) {
            log.error("[lbl][2087-消息推送][Announcement][PUSH] Knock推送失败, id={}, error={}", announcement.getId(), e.getMessage(), e);
        }
    }

    /**
     * 推送到 MM（通过 Feign 调用 XCollabSpace 机器人）
     */
    private void pushToMm(AnnouncementEntity announcement) {
        try {
            String mmContent = AnnouncementFormatConverter.toMmMarkdown(announcement.getContent());
            String fullMessage = "## " + announcement.getTitle() + "\n\n" + mmContent;

            String authToken = "Bearer " + mattermostProperties.getXcollabspaceBotToken();
            String channelId = mattermostProperties.getXcollabspaceChannelId();

            // 测试环境只打日志不发送
            if (systemProperties.isTestEnabled()) {
                log.info("[lbl][2087-消息推送][Announcement][PUSH] [测试环境-不发送] MM推送, id={}, channelId={}, messageLength={}",
                        announcement.getId(), channelId, fullMessage.length());
                return;
            }

            MattermostPostReq postReq = MattermostPostReq.builder()
                    .channelId(channelId)
                    .message(fullMessage)
                    .build();

            log.info("[lbl][2087-消息推送][Announcement][PUSH] 调用MM Feign推送公告, id={}, channelId={}, messageLength={}",
                    announcement.getId(), channelId, fullMessage.length());
            mattermostMessageFeign.createPost(authToken, false, postReq);
            log.info("[lbl][2087-消息推送][Announcement][PUSH] MM推送成功, id={}", announcement.getId());
        } catch (Exception e) {
            log.error("[lbl][2087-消息推送][Announcement][PUSH] MM推送失败, id={}, error={}", announcement.getId(), e.getMessage(), e);
        }
    }
}

