package com.yottastudios.ns.collabspace.shared.cache.service.impl;

import com.github.benmanes.caffeine.cache.Cache;
import com.github.benmanes.caffeine.cache.Caffeine;
import com.yottastudios.ns.collabspace.grpc.IApitableGrpcClientService;
import com.yottastudios.ns.collabspace.shared.cache.service.UserCacheService;
import com.yottastudios.ns.collabspace.user.vo.UserSimpleInfoVo;
import jakarta.annotation.Resource;
import org.springframework.stereotype.Service;

import java.util.concurrent.TimeUnit;

@Service
public class UserCacheInCaffeineServiceImpl implements UserCacheService {

    private static final int DEFAULT_NICKNAME_CACHE_EXPIRE_SECOND = (int) TimeUnit.DAYS.toSeconds(1);

    private final Cache<Long, NicknameCacheValue> nicknameCache = Caffeine.newBuilder()
            .maximumSize(10_000)
            .build();

    @Resource
    private IApitableGrpcClientService apitableGrpcClientService;

    @Override
    public String getNicknameByUserId(Long userId) {
        String nickname = getNicknameFromCache(userId);
        if (nickname != null) {
            return nickname;
        }

        UserSimpleInfoVo user = apitableGrpcClientService.getUserById(userId);
        if (user == null || user.getNickName() == null) {
            return null;
        }

        nickname = user.getNickName();
        saveNickname(userId, nickname, DEFAULT_NICKNAME_CACHE_EXPIRE_SECOND);
        return nickname;
    }

    @Override
    public void saveNickname(Long userId, String nickname, int expireSecond) {
        if (userId == null || nickname == null) {
            return;
        }
        if (expireSecond <= 0) {
            nicknameCache.invalidate(userId);
            return;
        }

        long expireAtMillis = System.currentTimeMillis() + TimeUnit.SECONDS.toMillis(expireSecond);
        nicknameCache.put(userId, new NicknameCacheValue(nickname, expireAtMillis));
    }

    private String getNicknameFromCache(Long userId) {
        if (userId == null) {
            return null;
        }

        NicknameCacheValue cacheValue = nicknameCache.getIfPresent(userId);
        if (cacheValue == null) {
            return null;
        }
        if (cacheValue.isExpired()) {
            nicknameCache.invalidate(userId);
            return null;
        }

        return cacheValue.nickname;
    }

    private static class NicknameCacheValue {
        private final String nickname;
        private final long expireAtMillis;

        private NicknameCacheValue(String nickname, long expireAtMillis) {
            this.nickname = nickname;
            this.expireAtMillis = expireAtMillis;
        }

        private boolean isExpired() {
            return System.currentTimeMillis() >= expireAtMillis;
        }
    }
}

