package com.yottastudios.ns.collabspace.third.feign;

import com.yottastudios.ns.collabspace.third.dto.migrate.MemberEntity;
import com.yottastudios.ns.collabspace.third.dto.migrate.NodeInfoTreeVo;
import com.yottastudios.ns.collabspace.third.dto.migrate.SpaceAdminInfo;
import com.yottastudios.ns.collabspace.third.dto.migrate.SpaceEntityDto;
import com.yottastudios.ns.collabspace.third.dto.migrate.SpaceControlInfo;
import com.yottastudios.ns.collabspace.third.dto.migrate.NodeFavoriteEntityDto;
import com.yottastudios.ns.collabspace.third.dto.migrate.SpaceShareInfoDto;
import org.springframework.cloud.openfeign.FeignClient;
import java.util.List;
import lombok.Data;
import org.springframework.web.bind.annotation.*;

/**
 * 一次性的, 用于迁移
 */
@FeignClient(name = "apitableMigrationFeign", url = "${apitable.host}")
public interface ApitableMigrationFeign {

    @GetMapping("/api/v1/aio/migration/spaces")
    ResponseData<List<SpaceEntityDto>> getSpaces();

    @GetMapping("/api/v1/aio/migration/spaces/{spaceId}/members")
    ResponseData<List<MemberEntity>> getSpaceMembers(@PathVariable("spaceId") String spaceId);

    @GetMapping("/api/v1/aio/migration/spaces/{spaceId}/admins")
    ResponseData<List<SpaceAdminInfo>> getSpaceAdmins(@PathVariable("spaceId") String spaceId);

    @GetMapping("/api/v1/aio/migration/spaces/{spaceId}/tree")
    ResponseData<NodeInfoTreeVo> getSpaceTree(@PathVariable("spaceId") String spaceId);

    @GetMapping("/api/v1/aio/migration/spaces/{spaceId}/controls")
    ResponseData<SpaceControlInfo> getSpaceControls(@PathVariable("spaceId") String spaceId);

    @GetMapping("/api/v1/aio/migration/spaces/{spaceId}/favorites")
    ResponseData<List<NodeFavoriteEntityDto>> getSpaceFavorites(@PathVariable("spaceId") String spaceId);

    @GetMapping("/api/v1/aio/migration/spaces/{spaceId}/shares")
    ResponseData<SpaceShareInfoDto> getSpaceShares(@PathVariable("spaceId") String spaceId);

    @Data
    class ResponseData<T> {
        private Boolean success;
        private Integer code;
        private String message;
        private T data;
    }
}

