import java.util.*;
import java.util.function.Function;
import java.util.stream.Collectors;

@Service
@Slf4j
public class UserManageQueryManagerImpl implements UserManageQueryManager {

    @Resource
    private IApitableGrpcClientService apitableGrpcClientService;
    @Resource
    private IUserTeamService userTeamService;
    @Resource
    private IUserTeamUserRelService userTeamUserRelService;
    @Resource
    private IUserProjectService userProjectService;
    @Resource
    private IUserProjectTeamRelService userProjectTeamRelService;
    @Resource
    private IViewUserTeamRelService viewUserTeamRelService;

    @Value("${mm-test-only-tag:false}")
    private boolean mmTestOnlyOnlyTag;

    @Resource
    private ConstProperties constProperties;
    @Resource
    private MattermostProperties mattermostProperties;
    @Resource
    private MattermostUserCacheService mattermostUserCacheService;

    @Override
    public List<UserInfoForManageVo> allUserList(Long userId){

        boolean internalNetwork = constProperties.isInternalNetwork();
        boolean mirror = constProperties.isMirror();

        List<UserSimpleInfoVo> allValidUsers;
        if((internalNetwork || mmTestOnlyOnlyTag) && !mirror){
            List<UserSimpleInfoVo> allServerUsers = apitableGrpcClientService.getAllValidUsers(userId);
            List<MattermostUserResp> mmUserList = getMMUserListFilterContractor(mattermostProperties.getMmXTeamId());
            if(CollectionUtils.isEmpty(mmUserList)||CollectionUtils.isEmpty(allServerUsers)) return List.of();
            List<String> userEmails = mmUserList.stream().map(MattermostUserResp::getEmail).toList();
            allValidUsers=allServerUsers.stream().filter(u -> (userEmails.contains(u.getEmail())||!u.getIsMmSync()||u.getStatus()==0)
                    && StringUtils.isNotBlank(u.getEmail())  && u.getEmail().endsWith("@yottastudios.com") ).toList();
            Map<String, String> mmNickNameMap = mmUserList.stream().collect(Collectors.toMap(MattermostUserResp::getEmail, MattermostUserResp::getNickname));
            allValidUsers.forEach(u -> {
                if(u.getIsMmSync()){
                    u.setNickName(mmNickNameMap.get(u.getEmail()));
                }
            });
        }else{
            allValidUsers = apitableGrpcClientService.getAllValidUsers(userId).stream().filter(u -> StringUtils.isNotBlank(u.getEmail()) && u.getEmail().endsWith("@yottastudios.com") ).toList();
        }

        if(CollectionUtils.isEmpty(allValidUsers))
            return  List.of();



        List<UserTeamEntity> allUserTeams = userTeamService.list();
        List<UserTeamUserRelEntity> allUserTeamUserRel = userTeamUserRelService.list();
        // 过滤掉删除和不在组中的关系
        allUserTeamUserRel = allUserTeamUserRel.stream().
                filter(o -> o.getIsDeleted().equals(BinaryOperationEnum.OFF.getValue()) &&
                        o.getIsInTeam().equals(BinaryOperationEnum.ON.getValue())).collect(Collectors.toList());
        List<UserProjectEntity> allUserProjects = userProjectService.list();
        List<UserProjectTeamRelEntity> allUserProjectTeamRel = userProjectTeamRelService.list();

        Map<Long, UserTeamEntity> userTeamMap=new HashMap<>();
        if(CollectionUtils.isNotEmpty(allUserTeams))
            userTeamMap = allUserTeams.stream().collect(Collectors.toMap(UserTeamEntity::getId, Function.identity()));

        Map<Long, List<UserTeamUserRelEntity>> userTeamRelMap=new HashMap<>();
        if(CollectionUtils.isNotEmpty(allUserTeamUserRel))
            userTeamRelMap = allUserTeamUserRel.stream().collect(Collectors.groupingBy(UserTeamUserRelEntity::getUserId));

        Map<Long, UserProjectEntity> userProjectMap=new HashMap<>();
        if(CollectionUtils.isNotEmpty(allUserProjects))
            userProjectMap = allUserProjects.stream().collect(Collectors.toMap(UserProjectEntity::getId, Function.identity()));

        Map<Long, UserProjectTeamRelEntity> projectTeamRelEntityMap=new HashMap<>();
        if(CollectionUtils.isNotEmpty(allUserProjectTeamRel))
            projectTeamRelEntityMap = allUserProjectTeamRel.stream().collect(Collectors.toMap(UserProjectTeamRelEntity::getTeamId, Function.identity()));


        List<UserInfoForManageVo> result=new ArrayList<>();

        for (UserSimpleInfoVo u : allValidUsers) {
            UserInfoForManageVo userInfoForManageVo = new UserInfoForManageVo();
            userInfoForManageVo.setUserInfo(u);

            List<UserTeamUserRelEntity> allRelTeams = userTeamRelMap.get(u.getId());
            if (CollectionUtils.isNotEmpty(allRelTeams)) {
