    @Override
    public List<UserInfoForManageVo> getUserNicknameLike(String nickname){

        boolean internalNetwork = constProperties.isInternalNetwork();
        boolean mirror = constProperties.isMirror();

        List<UserSimpleInfoVo> allValidUsers;
        if((internalNetwork || mmTestOnlyOnlyTag) && !mirror){
            List<UserSimpleInfoVo> allExistUsers = apitableGrpcClientService.getExistUsersByNicknameLike(nickname);
            List<MattermostUserResp> mmUserList = getMMUserListFilterContractor(mattermostProperties.getMmXTeamId());
            if(CollectionUtils.isEmpty(mmUserList)||CollectionUtils.isEmpty(allExistUsers)) return List.of();
            List<String> userEmails = mmUserList.stream().map(MattermostUserResp::getEmail).toList();
            allValidUsers=allExistUsers.stream().filter(u -> (userEmails.contains(u.getEmail())||!u.getIsMmSync())
                    && StringUtils.isNotBlank(u.getEmail())  && u.getEmail().endsWith("@yottastudios.com") ).toList();
            Map<String, String> mmNickNameMap = mmUserList.stream().collect(Collectors.toMap(MattermostUserResp::getEmail, MattermostUserResp::getNickname));
            allValidUsers.forEach(u -> {
                if(u.getIsMmSync()){
                    u.setNickName(mmNickNameMap.get(u.getEmail()));
                }
            });
        }else{
            allValidUsers = apitableGrpcClientService.getUsersLikeNickname(nickname);
            if(CollectionUtils.isNotEmpty(allValidUsers)) {
                allValidUsers = allValidUsers.stream().filter(u -> StringUtils.isNotBlank(u.getEmail()) && u.getEmail().endsWith("@yottastudios.com") ).toList();
            }
        }

        if(CollectionUtils.isEmpty(allValidUsers))
            return  List.of();

        List<Long> userIds = allValidUsers.stream().map(UserSimpleInfoVo::getId).toList();

        Map<Long, UserTeamEntity> userTeamMap=new HashMap<>();
        Map<Long, List<UserTeamUserRelEntity>> userTeamRelMap=new HashMap<>();
        Map<Long, UserProjectEntity> userProjectMap=new HashMap<>();
        Map<Long, UserProjectTeamRelEntity> projectTeamRelEntityMap=new HashMap<>();

        List<UserTeamUserRelEntity> allUserTeamUserRel = userTeamUserRelService.listInUserIds(userIds);
        if(CollectionUtils.isNotEmpty(allUserTeamUserRel)){
            userTeamRelMap = allUserTeamUserRel.stream().collect(Collectors.groupingBy(UserTeamUserRelEntity::getUserId));
            List<Long> teamIds = allUserTeamUserRel.stream().map(UserTeamUserRelEntity::getTeamId).toList().stream().distinct().toList();
            List<UserTeamEntity> allUserTeams = userTeamService.getBaseMapper().selectBatchIds(teamIds);
            if(CollectionUtils.isNotEmpty(allUserTeams)){
                userTeamMap = allUserTeams.stream().collect(Collectors.toMap(UserTeamEntity::getId, Function.identity()));
                List<UserProjectTeamRelEntity> allUserProjectTeamRel = userProjectTeamRelService.listInTeamIds(teamIds);
                if(CollectionUtils.isNotEmpty(allUserProjectTeamRel)){
                    projectTeamRelEntityMap = allUserProjectTeamRel.stream().collect(Collectors.toMap(UserProjectTeamRelEntity::getTeamId, Function.identity()));
                    List<Long> projectIds = allUserProjectTeamRel.stream().map(UserProjectTeamRelEntity::getProjectId).toList().stream().distinct().toList();
                    List<UserProjectEntity> allUserProjects = userProjectService.getBaseMapper().selectBatchIds(projectIds);
                    if(CollectionUtils.isNotEmpty(allUserProjects))
                        userProjectMap = allUserProjects.stream().collect(Collectors.toMap(UserProjectEntity::getId, Function.identity()));
                }
            }
        }

        List<UserInfoForManageVo> result=new ArrayList<>();

        for (UserSimpleInfoVo u : allValidUsers) {
            UserInfoForManageVo userInfoForManageVo = new UserInfoForManageVo();
            userInfoForManageVo.setUserInfo(u);

            List<UserTeamUserRelEntity> allRelTeams = userTeamRelMap.get(u.getId());
            if (CollectionUtils.isNotEmpty(allRelTeams)) {
                List<TeamInfoByUserVo> teamInfos=new ArrayList<>();
                for (UserTeamUserRelEntity rt : allRelTeams) {
                    UserTeamEntity userTeamEntity = userTeamMap.get(rt.getTeamId());
                    if (null == userTeamEntity) continue;
                    UserProjectTeamRelEntity userProjectTeamRelEntity = projectTeamRelEntityMap.get(userTeamEntity.getId());
                    if (null == userProjectTeamRelEntity) continue;
                    UserProjectEntity userProjectEntity = userProjectMap.get(userProjectTeamRelEntity.getProjectId());
                    if (null == userProjectEntity) continue;

                    teamInfos.add(new TeamInfoByUserVo(userTeamEntity,rt,userProjectEntity));

                }
                userInfoForManageVo.setTeamInfos(teamInfos);
            }
            result.add(userInfoForManageVo);
        }

        return result;

    }

