    private List<MattermostUserResp> getMMUserListFilterContractor(String teamId){
        List<MattermostUserResp> mmUserList = mattermostUserCacheService.getMMUserList(teamId);
        List<MattermostGroupResp> usersWithTeam = mattermostUserCacheService.getUsersWithTeam(teamId);
        List<MattermostGroupResp> contractorTeam =
                usersWithTeam.stream().filter(t -> t.getDisplaygroupname().toLowerCase().startsWith("expat")).toList();
        if(CollectionUtils.isNotEmpty(contractorTeam)){
            Set<String> contractorUserEmails = new HashSet<>();
            contractorTeam.forEach(ct->{
                List<MattermostGroupResp.UserSimpleResp> users = ct.getUsers();
                if(CollectionUtils.isNotEmpty(users))
                    users.forEach(user-> contractorUserEmails.add(user.getEmail()));
            });
            if(CollectionUtils.isNotEmpty(contractorUserEmails))
                mmUserList = mmUserList.stream().filter(x->!contractorUserEmails.contains(x.getEmail())).toList();
        }
        return mmUserList;
    }




    @Override
    public DataForInternalExportDto allUserListForInternalExport() {

        boolean internalNetwork = constProperties.isInternalNetwork();

        if (!internalNetwork && !mmTestOnlyOnlyTag)
            return null;

        boolean mirror = constProperties.isMirror();
        if(mirror) return null;

        List<UserSimpleInfoVo> allServerUsers = apitableGrpcClientService.getAllValidUsers(-1L);
        List<MattermostUserResp> mmUserList = getMMUserListFilterContractor(mattermostProperties.getMmXTeamId());
        if(CollectionUtils.isEmpty(mmUserList)||CollectionUtils.isEmpty(allServerUsers)) return null;
        List<String> userEmails = mmUserList.stream().map(MattermostUserResp::getEmail).toList();
        List<UserSimpleInfoVo> allValidUsers=allServerUsers.stream().filter(u -> (userEmails.contains(u.getEmail())||!u.getIsMmSync()||u.getStatus()==0)
                && StringUtils.isNotBlank(u.getEmail()) && u.getEmail().endsWith("@yottastudios.com")).toList();
        Map<String, String> mmNickNameMap = mmUserList.stream().collect(Collectors.toMap(
                        MattermostUserResp::getEmail, MattermostUserResp::getNickname,
                        (oldVal, newVal) -> oldVal
                ));
        allValidUsers.forEach(u -> {
            if(u.getIsMmSync()){
                u.setNickName(mmNickNameMap.get(u.getEmail()));
            }
        });


        DataForInternalExportDto result = new DataForInternalExportDto();

        List<UserInfoForInternalExportDto> allUsers = new ArrayList<>();

        for(UserSimpleInfoVo user : allValidUsers){
            UserInfoForInternalExportDto userDto = UserInfoForInternalExportDto.builder().nickName(user.getNickName()).email(user.getEmail()).
                    isProjectX("1").status("0").build();
            allUsers.add(userDto);
        }

        result.setAllUsers(allUsers);

        Map<Long, UserSimpleInfoVo> allExistUserIdMap = allValidUsers.stream().collect(Collectors.toMap(UserSimpleInfoVo::getId, Function.identity()));

        List<TeamInfoForInternalExportDto> memberList = new ArrayList<>();
        List<TeamInfoForInternalExportDto> viewerList = new ArrayList<>();

        List<UserProjectEntity> mmProjectList = userProjectService.list().stream().filter(x -> StringUtils.isNotBlank(x.getMattermostId())).toList();
        if (CollectionUtils.isNotEmpty(mmProjectList)) {
            List<UserTeamEntity> allUserTeams = userTeamService.list();
            if (CollectionUtils.isNotEmpty(allUserTeams)) {
                Map<Long, String> userTeamNameMap = allUserTeams.stream().collect(Collectors.toMap(UserTeamEntity::getId, UserTeamEntity::getTeamName));
                Map<Long, String> userTeamGroupIdMap = allUserTeams.stream()
                        .collect(Collectors.toMap(
                                UserTeamEntity::getId,
                                x -> StringUtils.isNotBlank(x.getMattermostId())
                                        ? x.getMattermostId()
                                        : String.valueOf(x.getId())
                        ));
                for (UserProjectEntity project : mmProjectList) {
                    List<UserProjectTeamRelEntity> userProjectTeamRelList = userProjectTeamRelService.listByProjectId(project.getId());
                    if (CollectionUtils.isEmpty(userProjectTeamRelList))
                        continue;

                    String projectName = project.getProjectName();

                    List<Long> allTeamIds = userProjectTeamRelList.stream().map(UserProjectTeamRelEntity::getTeamId).toList();
                    List<UserTeamUserRelEntity> userTeamUserRelList = userTeamUserRelService.listInTeamIds(allTeamIds);
                    List<ViewUserTeamRelEntity> viewUserTeamRelList = viewUserTeamRelService.listInTeamIds(allTeamIds);

                    //组员
                    Map<Long, List<UserTeamUserRelEntity>> userTeamRelMap = userTeamUserRelList.stream().collect(Collectors.groupingBy(UserTeamUserRelEntity::getTeamId));
                    userTeamRelMap.forEach((teamId, v) -> {
                        if (CollectionUtils.isNotEmpty(v)) {
                            v.forEach(u -> {
                                UserSimpleInfoVo userSimpleInfoVo = allExistUserIdMap.get(u.getUserId());
                                if(null!=userSimpleInfoVo){
                                    memberList.add(TeamInfoForInternalExportDto.builder().
                                            projectName(projectName).teamName(userTeamNameMap.get(teamId)).mmGroupId(userTeamGroupIdMap.get(teamId)).
                                            nickName(userSimpleInfoVo.getNickName()).email(userSimpleInfoVo.getEmail()).build());
                                }
                            });
                        }
                    });

                    //可见用户
                    Map<Long, List<ViewUserTeamRelEntity>> viewerTeamRelMap = viewUserTeamRelList.stream().collect(Collectors.groupingBy(ViewUserTeamRelEntity::getTeamId));
                    viewerTeamRelMap.forEach((teamId, v) -> {
                        if (CollectionUtils.isNotEmpty(v)) {
                            v.forEach(u -> {
                                UserSimpleInfoVo userSimpleInfoVo = allExistUserIdMap.get(u.getUserId());
                                if(null!=userSimpleInfoVo){
                                    viewerList.add(TeamInfoForInternalExportDto.builder().
                                            projectName(projectName).teamName(userTeamNameMap.get(teamId)).mmGroupId(userTeamGroupIdMap.get(teamId)).
                                            nickName(userSimpleInfoVo.getNickName()).email(userSimpleInfoVo.getEmail()).build());
                                }
                            });
                        }
                    });
                }

                result.setMemberList(memberList);
                result.setViewerList(viewerList);

            }

        }
        return result;

    }

    @Override
    public XSSFWorkbook exportUserManageDataToExcel(DataForInternalExportDto data){

        // 1. 创建工作簿和工作表
        XSSFWorkbook workbook = new XSSFWorkbook();

        POIXMLProperties.CoreProperties coreProps = workbook.getProperties().getCoreProperties();
        try {
            coreProps.setCreated("2023-01-01T12:00:00Z");

        } catch (InvalidFormatException e) {
            System.err.println("设置创建时间失败: " + e.getMessage());
        }

        // 2. 创建表格
        if(null==data){
            workbook.createSheet("全部成员");
            workbook.createSheet("小组成员列表");
            workbook.createSheet("小组可见成员列表");
            return workbook;
        }

        //sheet1
        List<UserInfoForInternalExportDto> allUsers = data.getAllUsers();
        Sheet allUserSheet = workbook.createSheet("全部成员");
        if(CollectionUtils.isNotEmpty(allUsers)){
            String[] headers = new String[4];
            headers[0]="花名";
            headers[1]="邮箱";
            headers[2]="是否禁用";
            headers[3]="是否projectX成员";
            Row headerRow = allUserSheet.createRow(0);
            for (int j = 0; j < headers.length; j++) {
                Cell cell = headerRow.createCell(j);
                cell.setCellValue(headers[j]);
                allUserSheet.setColumnWidth(j, 32* 128);
            }
            for (int j = 0; j < allUsers.size(); j++) {
                Row row = allUserSheet.createRow(j+1);

                UserInfoForInternalExportDto record = allUsers.get(j);
                row.createCell(0).setCellValue(record.getNickName());
                row.createCell(1).setCellValue(record.getEmail());
                row.createCell(2).setCellValue(record.getStatus());
                row.createCell(3).setCellValue(record.getIsProjectX());
            }
        }


        //sheet2
        List<TeamInfoForInternalExportDto> memberList = data.getMemberList();
        Sheet memberListSheet = workbook.createSheet("小组成员列表");
        if(CollectionUtils.isNotEmpty(memberList)){
            String[] headers = new String[5];
            headers[0]="项目名称";
            headers[1]="小组名称";
            headers[2]="mmGroupId";
            headers[3]="花名";
            headers[4]="邮箱";
            Row headerRow = memberListSheet.createRow(0);
            for (int j = 0; j < headers.length; j++) {
                Cell cell = headerRow.createCell(j);
                cell.setCellValue(headers[j]);
                memberListSheet.setColumnWidth(j, 32* 128);
            }
            for (int j = 0; j < memberList.size(); j++) {
                Row row = memberListSheet.createRow(j+1);

                TeamInfoForInternalExportDto record = memberList.get(j);
                row.createCell(0).setCellValue(record.getProjectName());
                row.createCell(1).setCellValue(record.getTeamName());
                row.createCell(2).setCellValue(record.getMmGroupId());
                row.createCell(3).setCellValue(record.getNickName());
                row.createCell(4).setCellValue(record.getEmail());
            }
        }

        //sheet3
        List<TeamInfoForInternalExportDto> viewerList = data.getViewerList();
        Sheet viewerListSheet = workbook.createSheet("小组可见成员列表");
        if(CollectionUtils.isNotEmpty(viewerList)){
            String[] headers = new String[5];
            headers[0]="项目名称";
            headers[1]="小组名称";
            headers[2]="mmGroupId";
            headers[3]="花名";
            headers[4]="邮箱";
            Row headerRow = viewerListSheet.createRow(0);
            for (int j = 0; j < headers.length; j++) {
                Cell cell = headerRow.createCell(j);
                cell.setCellValue(headers[j]);
                viewerListSheet.setColumnWidth(j, 32* 128);
            }
            for (int j = 0; j < viewerList.size(); j++) {
                Row row = viewerListSheet.createRow(j+1);

                TeamInfoForInternalExportDto record = viewerList.get(j);
                row.createCell(0).setCellValue(record.getProjectName());
                row.createCell(1).setCellValue(record.getTeamName());
                row.createCell(2).setCellValue(record.getMmGroupId());
                row.createCell(3).setCellValue(record.getNickName());
                row.createCell(4).setCellValue(record.getEmail());
            }
        }



        return workbook;

    }


